<template>
  <div
    ref="number"
    class="wrap-container"
    :style="{
      'font-size': chartSetting.fontSize ? chartSetting.fontSize + 'px' : '',
      width: wrapWidth ? wrapWidth : 'auto'
    }"
  ></div>
</template>
<script>
export default {
  name: "digital",
  data () {
    return {
      value: this.number.num,
      // value: 65656,
      html: ""
    };
  },
  methods: {
    init () {
      if (this.value || Number(this.value) === 0) {
        let self = this
        let html = ""
        this.value.toString().split('').forEach(v => {
          html += `<div class="digit-wrap"><ul class="list scroll${v}">`
          for (let i = 0; i <= 9; i++) {
            html += `<li style="color:${this.chartSetting.color}">${i}</li>`
          }
          html += '</ul></div>'
        })
        this.$refs.number.innerHTML = html
      }
    }
  },
  updated () {
    this.init();
  },
  computed: {
    wrapWidth () {
      if (this.value) {
        let length = this.value.toString().split('').length
        let fontSize = Number(this.chartSetting.fontSize)
        // return fontSize * length + 'px'
        return null
      }
    }
  },
  props: {
    number: {
      type: Object,
      default: () => { { num: 0 } }
    },
    chartSetting: {
      type: Object,
      default: () => { }
    }
  },
  watch: {
    number: {
      deep: true,
      handler (newValue, oldValue) {
        this.value = newValue.num;
        this.init();
        return newValue;
      }
    }
  }
};
</script>
<style>
.wrap-container {
  display: flex;
  justify-content: center;
}
.digit-wrap {
  width: 20px;
  height: 50px;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  /* font-size: 50px; */
}
.list {
  position: absolute;
  left: 0;
  top: 0;
  margin: 0;
  padding: 0;
  height: 100%;
  box-sizing: border-box;
}
.list li {
  list-style: none;
  width: 20px;
  height: 50px;
  line-height: 50px;
  color: #123123;
  text-align: center;
  float: left;
  box-sizing: border-box;
}
@keyframes move9 {
  0% {
    top: 0;
  }
