<template>
  <div class="data-preview">
    <div class="title_box">
      <div class="title">{{modelConfig.model_name}}</div>
      <el-button @click="exportExcel" type="primary" class="export-button" width="200px">еѓЉеЗЇдЄЇExcel</el-button>
    </div>

    <el-table
      :data="tableData"
      border
      style="width: 100%"
      stripe
      fixed
      v-if="tableData&&tableTitle"
      id="out-table"
    >
      <template v-for="(only,i) in tableTitle">
        <el-table-column :key="i" :prop="only.columns" :label="only.label"></el-table-column>
      </template>
    </el-table>
    <div class="pagination">
      <el-pagination
        @size-change="previewDataSizeChange"
        @current-change="previewDataCurrentChange"
        :current-page="previewInfo.currentPage"
        :page-sizes="[10, 50, 100, 200]"
        :page-size="previewInfo.rowNum"
        layout="total, sizes, prev, pager, next, jumper"
        :total="previewInfo.totalPage"
        v-if="tableData"
      ></el-pagination>
    </div>
  </div>
</template>

<script>
import moment from "moment";
import FileSaver from "file-saver";
import XLSX from "xlsx";
export default {
  name: "dataPreview",
  data() {
    return {
      previewInfo: {
        // previewTableеИЖй°µйЕНзљЃдњ°жБѓ
        currentPage: 1,
        rowNum: 0,
        totalPage: 0
      },
      tableTitle: [],
      tableData: [],
      appName: "",
      serviceName: "",
      modelConfig: "",
      requestBody: "", //иѓЈж±ВдљУ
      columnsOption: "" //жЙАжЬЙеИЧ
    };
  },
  methods: {
    exportExcel() {
      let time = moment().format("YYYYMMDDHHmmss");
      let fileName = this.serviceName + time + ".xlsx";
      // е∞ЖйҐДиІИи°®ж†ЉдЄ≠зЪДжХ∞жНЃеѓЉеЗЇдЄЇexcel
      let wb = XLSX.utils.table_to_book(document.querySelector("#out-table"));
      /* иОЈеПЦдЇМињЫеИґе≠Чзђ¶дЄ≤дљЬдЄЇиЊУеЗЇ */
      let wbout = XLSX.write(wb, {
        bookType: "xlsx",
        bookSST: true,
        type: "array"
      });
      try {
        FileSaver.saveAs(
          //Blob еѓєи±°и°®з§ЇдЄАдЄ™дЄНеПѓеПШгАБеОЯеІЛжХ∞жНЃзЪДз±їжЦЗдїґеѓєи±°гАВ
          //Blob и°®з§ЇзЪДдЄНдЄАеЃЪжШѓJavaScriptеОЯзФЯж†ЉеЉПзЪДжХ∞жНЃгАВ
          //File жО•еП£еЯЇдЇОBlobпЉМзїІжЙњдЇЖ blob зЪДеКЯиГљеєґе∞ЖеЕґжЙ©е±ХдљњеЕґжФѓжМБзФ®жИЈз≥їзїЯдЄКзЪДжЦЗдїґгАВ
          //ињФеЫЮдЄАдЄ™жЦ∞еИЫеїЇзЪД Blob еѓєи±°пЉМеЕґеЖЕеЃєзФ±еПВжХ∞дЄ≠зїЩеЃЪзЪДжХ∞зїДдЄ≤иБФзїДжИРгАВ
          new Blob([wbout], { type: "application/octet-stream" }),
          //иЃЊзљЃеѓЉеЗЇжЦЗдїґеРНзІ∞
          fileName
        );
      } catch (e) {
        
      }
      return wbout;
    },
    getRequestBody() {
      let modelConfig = this.modelConfig;
      if (modelConfig) {
        let endData = modelConfig.endData;
        let req = {
          serviceName: modelConfig.serviceName,
          colNames: ["*"],
          condition: endData.condition,
          group: endData.group.concat(endData.aggregation),
          order: endData.order
        };
        this.requestBody = req;
        this.getPreviewTableData();
      }
    },
    getPreviewTableData() {
      let self = this;
      let req = this.requestBody;
      let url = this.getServiceUrl("select", this.serviceName, this.appName);
      self.tableTitle = [];
      req.page = {
        pageNo: this.previewInfo.currentPage,
        rownumber: this.previewInfo.rowNum || 10
      };
      this.axios
        .post(url, req)
        .then(res => {
          let pageData = res.data.page; //иОЈеПЦеИЖй°µдњ°жБѓ
          this.tableData = res.data.data;
         
          this.previewInfo.currentPage = pageData.pageNo;
          this.previewInfo.rowNum = pageData.rownumber;
          this.previewInfo.totalPage = pageData.total;
          //зВєеЗїеРОеЗЇеЕИи°®ж†Љ
          //и°®е§іжХ∞зїД
          let tableAllTitleData = self.requestBody.group;
          if (tableAllTitleData.length === 0) {
            self.tableTitle = self.columnsOption;
          } else {
            tableAllTitleData.forEach(item => {
              if (item.type) {
                self.columnsOption.forEach(col => {
                  if (item.colName === col.columns) {
                    self.tableTitle.push(col);
                  }
                });
              } else {
                self.tableTitle = self.columnsOption;
              }
            });
          }
          //и°®ж†ЉеЖЕеЃєжХ∞жНЃ
        })
        .catch(err => {
          
        });
    },
    getModelConfig(modelId) {
      if (modelId) {
        this.modelId = modelId;
        let serviceName = "srvanalyze_model_select";
        let url = this.getServiceUrl("select", serviceName, "dataanalyze");
        let params = {
          serviceName: "srvanalyze_model_select",
          colNames: ["*"],
          condition: [
            {
              colName: "model_no",
              ruleType: "eq",
              value: modelId
            }
          ]
        };
        this.axios
          .post(url, params)
          .then(res => {
            
            let data = res.data.data;
            if (data.length > 0) {
              data = data[0];
              this.appName = data.belong_app;
              this.serviceName = data.service_name;
              this.modelConfig = data.model_config
                ? JSON.parse(data.model_config)
                : "жЪВжЧ†жХ∞жНЃ";
              // this.setModelConfig(this.modelConfig)
              this.columnsOption = this.modelConfig.columnsOption;
              this.getRequestBody(); // иОЈеПЦиѓЈж±ВдљУ
            }
            
          })
          .catch(err => {
           
          });
      }
    },
    previewDataSizeChange(val) {
      this.previewInfo.rowNum = val;
      this.getPreviewTableData(this.requestBody);
     
    },
    previewDataCurrentChange(val) {
      
      this.previewInfo.currentPage = val;
      this.getPreviewTableData(this.requestBody);
    }
  },
  mounted() {
    let modelId = this.$route.params.modelId;
    if (modelId) {
      this.getModelConfig(modelId);
    }
  }
};
</script>

<style lang="scss" scoped>
.data-preview {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  zoom: 1;
  // width: 70%;
  margin: 8px;
  // padding-top: 100px;
  box-sizing: border-box;
  // height: 700px;
  .title_box {
    display: flex;
    justify-content: space-between;
    margin: 20px 0px;
    .title {
      color: #333;
      // line-height: 50px;
      font-size: 18px;
      font-weight: 600;
    }
  }
}
.pagination {
  text-align: center;
  margin: 20px;
}
.btn_box {
  display: flex;
  justify-content: flex-end;
  margin: 20px 8px;
}
</style>